/** partnerPointSettleMapper.updateJejuPointMst */

UPDATE  MSP_PARTNER_POINT_MST A
SET     PAY_RESULT = #{payResult}
        , RESULT_DTL_CD = #{responseCode}
        , PAY_POINT = DECODE(#{payResult}, 'S', REQ_POINT, PAY_POINT)
        , PAY_DTTM = SYSDATE
        , RVISN_ID = 'POINT'
        , RVISN_DTTM = SYSDATE
WHERE   A.SEND_FLAG = 'R'
AND     A.FULL_PAY_YN = 'Y'
AND     A.PAY_RESULT <> 'S'
AND     A.PARTNER_ID = #{partnerId}
AND     A.BILL_YM <=  #{billYm}
AND     A.CUSTOMER_ID IN (SELECT CUSTOMER_ID FROM MSP_JUO_CUS_INFO WHERE SELF_CSTMR_CI = #{memberCi} )

/** partnerPointSettleMapper.updatePartnerJejuair */
UPDATE  MSP_PARTNER_JEJUAIR_01
SET     RESULT_DTL_CD = #{responseCode}
        , RVISN_ID = 'POINT'
        , RVISN_DTTM = SYSDATE
WHERE   BILL_YM = #{billYm}
AND     MEMBER_CI = #{memberCi}

