/** partnerPointSettleMapper.insertPointFile */
INSERT INTO MSP_PARTNER_POINT_FILE
    (
        PARTNER_ID
        , FILE_NM
        , LOCAL_UP_DIR
        , LOCAL_DOWN_DIR
        , HOST_UP_DIR
        , HOST_DOWN_DIR
        , SEND_FLAG
        , SEND_RESULT
        , REGST_ID
        , REGST_DTTM
    ) VALUES (
        #{partnerId}
        , #{fileNm}
        , #{localUpDir}
        , #{localDownDir}
        , #{hostUpDir}
        , #{hostDownDir}
        , 'R'
        , 'R'
        , 'POINT'
        , SYSDATE
    )

