/* partnerPointSettleMapper.updatePointFileUp */
UPDATE  MSP_PARTNER_POINT_FILE
SET     SEND_FLAG = #{sendFlag}
        , REGST_ID = 'POINT'
        , REGST_DTTM = SYSDATE
WHERE   PARTNER_ID = #{partnerId}
AND     FILE_NM = #{fileNm}

/* partnerPointSettleMapper.updatePointFileDown */
UPDATE  MSP_PARTNER_POINT_FILE
SET     SEND_RESULT = #{sendResult}
        , RVISN_ID = 'POINT'
        , RVISN_DTTM = SYSDATE
WHERE   PARTNER_ID = #{partnerId}
AND     FILE_NM = DECODE(#{partnerId}, 'lpoint', REPLACE(#{fileNm}, 'O941', 'O940'), #{fileNm})

mapper.select:
/* partnerPointSettleMapper.getPointFileUpList */ SELECT A.PARTNER_ID , A.FILE_NM , A.LOCAL_UP_DIR , A.HOST_UP_DIR FROM MSP_PARTNER_POINT_FILE A WHERE A.SEND_FLAG <> 'S'
AND PARTNER_ID = #{partnerId}
AND FILE_NM LIKE #{fileNm} || '%'

/* partnerPointSettleMapper.getPointFileDownList */
SELECT  A.PARTNER_ID
        , DECODE(A.PARTNER_ID, 'lpoint', REPLACE(A.FILE_NM, 'O940', 'O941'), A.FILE_NM) AS FILE_NM 
        , A.LOCAL_DOWN_DIR
        , A.HOST_DOWN_DIR
FROM    MSP_PARTNER_POINT_FILE A
WHERE   SEND_FLAG = 'S'
AND     SEND_RESULT IN ('R', 'F')

	AND A.PARTNER_ID = #{partnerId}


	AND A.FILE_NM = #{fileNm}

/* partnerPointSettleMapper.getPointFileReadList */
SELECT  A.PARTNER_ID
        , DECODE(A.PARTNER_ID, 'lpoint', REPLACE(A.FILE_NM, 'O940', 'O941'), A.FILE_NM) AS FILE_NM
        , A.LOCAL_DOWN_DIR
FROM    MSP_PARTNER_POINT_FILE A
WHERE   A.SEND_FLAG = 'S'
AND     A.SEND_RESULT = 'D'

	AND A.PARTNER_ID = #{partnerId}


	AND A.FILE_NM = #{fileNm}

/* partnerPointSettleMapper.getPartnerSubList */
SELECT  IF_NO
        , UP_DIR
        , DOWN_DIR
FROM    MSP_PARTNER_SUB
WHERE   IF_NO = #{ifNo}

mapper.insert:
/* partnerPointSettleMapper.insertInsrMemberMst */ INSERT INTO MSP_INSR_MEMBER_MST ( CONTRACT_NUM , END_DTTM , STRT_DTTM , SVC_CNTR_NO , CUSTOMER_ID , RATE_CD , STAT_CD , AGE , BIRTH_DT , MINOR_AGENT_NM , MINOR_AGENT_TEL , REGST_DTTM , RVISN_DTTM )
SELECT A.CONTRACT_NUM , #{endDttm, jdbcType=VARCHAR} AS END_DTTM , #{strtDttm, jdbcType=VARCHAR} AS STRT_DTTM , A.SVC_CNTR_NO , A.CUSTOMER_ID , #{rateCd, jdbcType=VARCHAR} AS RATE_CD , #{statCd, jdbcType=VARCHAR} AS STAT_CD , FN_GET_AGE('X', A.CONTRACT_NUM) AS AGE , (CASE WHEN SUBSTR(CRYPTO_AES256.DEC_AES(USER_SSN), 7, 1) IN ('1','2','5','6') THEN '19' WHEN SUBSTR(CRYPTO_AES256.DEC_AES(USER_SSN), 7, 1) IN ('3','4','7','8') THEN '20' ELSE '18' END) || SUBSTR(CRYPTO_AES256.DEC_AES(USER_SSN), 1, 6) AS BIRTH_DT , (CASE WHEN FN_GET_AGE('X', A.CONTRACT_NUM) < 15 THEN C.MINOR_AGENT_NAME ELSE '' END ) AS MINOR_AGENT_NM , (CASE WHEN FN_GET_AGE('X', A.CONTRACT_NUM) < 15 THEN C.MINOR_AGENT_TEL_FN || C.MINOR_AGENT_TEL_MN || MINOR_AGENT_TEL_RN ELSE '' END ) AS MINOR_AGENT_TEL , SYSDATE , SYSDATE FROM MSP_JUO_SUB_INFO A , MSP_REQUEST B , MSP_REQUEST_AGENT C WHERE A.CONTRACT_NUM = #{contractNum, jdbcType=VARCHAR} AND A.CONTRACT_NUM = B.CONTRACT_NUM(+) AND B.OPER_TYPE(+) IN ('NAC3', 'MNP3') AND B.REQUEST_KEY = C.REQUEST_KEY(+)
AND NOT EXISTS (SELECT 1 FROM MSP_INSR_MEMBER_MST WHERE CONTRACT_NUM = #{contractNum, jdbcType=VARCHAR} AND END_DTTM = '99991231235959')

mapper.update:
/* partnerPointSettleMapper.updateInsrMemberMst */
UPDATE MSP_INSR_MEMBER_MST
SET     RVISN_DTTM = SYSDATE

        , END_DTTM = #{endDttm, jdbcType=VARCHAR}


        , RATE_CD = #{rateCd, jdbcType=VARCHAR}


        , STAT_CD = #{statCd, jdbcType=VARCHAR}

WHERE   CONTRACT_NUM = #{contractNum, jdbcType=VARCHAR}
AND     END_DTTM = '99991231235959'

mapper.select:
/* partnerPointSettleMapper.checkInsrMemberMst */
SELECT  COUNT(1)
FROM    MSP_INSR_MEMBER_MST
WHERE   CONTRACT_NUM = #{contractNum}
AND     TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN STRT_DTTM AND END_DTTM

mapper.delete:
/* partnerPointSettleMapper.deletePointFile */
DELETE FROM MSP_PARTNER_POINT_FILE
WHERE  PARTNER_ID = #{partnerId, jdbcType=VARCHAR}
AND    FILE_NM = #{fileNm, jdbcType=VARCHAR}

